#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int t,n,m,a[2][N],b[2][N],la[2],lb[2];
long long suma,sumb;
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        la[0]=la[1]=suma=0;
        for(int i=1,num;i<=n;i++){
            scanf("%d",&num);
            if(num<0)
                a[0][++la[0]]=num;
            else
                a[1][++la[1]]=num,suma+=num;
        }
        scanf("%d",&m);
        lb[0]=lb[1]=sumb=0;
        for(int i=1,num;i<=m;i++){
            scanf("%d",&num);
            if(num<0)
                b[0][++lb[0]]=num;
            else
                b[1][++lb[1]]=num,sumb+=num;
        }
        sort(a[0]+1,a[0]+la[0]+1);
        sort(a[1]+1,a[1]+la[1]+1);
        sort(b[0]+1,b[0]+lb[0]+1);
        sort(b[1]+1,b[1]+lb[1]+1);
        if(la[0] && lb[0])
            printf("%lld\n",suma+sumb);
        else if(!la[0] && !lb[0])
            printf("%lld\n",suma+sumb-a[1][1]-b[1][1]);
        else if(la[0] && !la[0]){
            long long ans=suma+sumb-b[1][1];
            for(int i=3,j=2;i<=la[0];i++){ // i枚举A中的负数，j枚举B中的非负数
                if(j<=lb[1] && b[j][1]<(-a[i][0]))
                    ans-=b[j][1],j++;
                else
                    ans+=a[i][0];
            }
            printf("%lld\n",ans);
        }else{
            long long ans=suma+sumb-a[1][1];
            for(int i=3,j=2;i<=lb[0];i++){ // i枚举B中的负数，j枚举A中的非负数
                if(j<=la[1] && a[j][1]<(-b[i][0]))
                    ans-=a[j][1],j++;
                else
                    ans+=b[i][0];
            }
            printf("%lld\n",ans);
        }
    }
    return 0;
}
